class Solution:
    def minSteps(self, n):
        # BFS over (length, clipboard) states
        from collections import deque
        if n == 1:
            return 0
        start = (1, 0)
        seen = {start}
        q = deque([(start, 0)])
        while q:
            (length, clip), steps = q.popleft()
            # copy all
            nxt = (length, length)
            if nxt not in seen and length <= n:
                if length == n:
                    return steps
                seen.add(nxt)
                q.append((nxt, steps + 1))
            # paste
            if clip > 0:
                nl = length + clip
                if nl <= n:
                    st = (nl, clip)
                    if nl == n:
                        return steps + 1
                    if st not in seen:
                        seen.add(st)
                        q.append((st, steps + 1))
        return -1

